mapper.select:
select 
	CUNAMLC as cunamlc , PAKLBKY as paklbky
from  WSLBMA
 where 1=1
  and COMPKEY = #{compkey}
  and WAREKEY = #{warekey}
  and OWNERKY = #{ownerky}		
  and CUSTKEY = #{custkey}

select COMPKEY, INVHSEQ, INVITNO, INVCATE, ROWGRID, ZZCOL01, ZZCOL02, ZZCOL03, ZZCOL04
  from OINVTH
 where COMPKEY = #{compkey}
   and INVHSEQ = #{invhseq}
 order by COMPKEY, INVHSEQ, INVITNO

select concat(SH.COMPKEY, SH.WAREKEY, SH.ALLGRKY, TS.PICKTYP) as rowkey , SH.COMPKEY as compkey , SH.WAREKEY as warekey , SH.OWNERKY as ownerky , TS.ALLGRKY as allgrky , TS.PICKTYP as picktyp , count(distinct SH.REFSODC) as resocnt , count(distinct SH.SKUMKEY) as skkycnt , count(distinct SH.CUSTKEY) as ctkycnt , count(distinct SH.RETAKEY) as rtkycnt , sum(SH.SHCUQTY) as shcuqty , sum(SH.RGITQTY) as rgitqty , sum(SH.SHALQTY) as shalqty , sum(TS.FORDQTY) as fordqty , sum(TS.TCMPQTY) as tcmpqty , sum(TS.SHDVSQT) as shdvsqt , sum(TS.SHDVEQT) as shdveqt , sum(SH.SHCFQTY) as shcfqty , date_format(max(SH.SHPSDAY), '%Y-%m-%d') as credate , date_format(max(SH.SHPSTIM), '%H-%i-%s') as CRETIME , max(SH.LMOUSER) as creuser , fn_sy_usernam(SH.COMPKEY, max(SH.LMOUSER)) as crename from WSHPIT SH inner join MCUSMA MC on MC.COMPKEY = SH.COMPKEY and MC.CUSTKEY = SH.RETAKEY inner join ( select COMPKEY, WAREKEY, OWNERKY, ALLGRKY, PICKTYP, REFSODC, REFSOIT , sum(FORDQTY) as fordqty, sum(TCMPQTY) as tcmpqty , sum(SHDVSQT) as shdvsqt, sum(SHDVEQT) as shdveqt from WTAKIT t where 1=1 and t.COMPKEY = #{compkey}
and t.OWNERKY = #{ownerky}
and t.DOCCATE = '500' and t.DOCTYPE = '520'
and t.TASKSTS not in ('CANCEL')
and t.TASKSTS not in ('CANCEL' ,'SHPOUT')
group by REFSODC, REFSOIT ) TS on SH.COMPKEY = TS.COMPKEY and SH.WAREKEY = TS.WAREKEY and SH.OWNERKY = TS.OWNERKY and SH.REFSODC = TS.REFSODC and SH.REFSOIT = TS.REFSOIT where 1=1 and SH.COMPKEY = #{compkey}
and SH.WAREKEY = #{warekey}
and SH.SHPPDAY BETWEEN replace(#{posdtft} , '-' ,'') AND replace(#{posdttt} , '-' ,'')
and SH.OWNERKY = #{ownerky}
and SH.CUSTKEY = #{custkey}
and MC.CUNAMLC like concat('%' , #{cunamlc} , '%')
and SH.REFSODC = #{refsodc}
and SH.DOCCATE = '700' and SH.DOCTYPE in ('720','750','760') and trim(TS.ALLGRKY) != '' and trim(TS.PICKTYP) != '' group by SH.COMPKEY, SH.OWNERKY, SH.WAREKEY, TS.ALLGRKY, TS.PICKTYP having sum(SH.SHALQTY) > 0

select CONCAT(OS.COMPKEY , OS.COOUTKY) as rowkey , OS.COMPKEY as compkey , date_format(OS.POSTDAT, '%Y-%m-%d') as postdat , MH.CUNAMLC as custnam , MC.CUNAMLC as retanam , OS.COOUTKY as cooutky , fn_om_cooutxt(OS.COOUTKY) as COOUTXT, max(OH.RMKCOOR) as rmkcoor, ifnull(OH.PAYORTY,'') as payorty , GROUP_CONCAT(distinct(select COMCDTX from MCODEM C where C.COMPKEY = '000' and C.COMCDKY = 'PAYTYPE' and C.COMCDVL = OS.PAYTYPE order by C.COMCDOR) ) as payortx , OH.VIAMTYN as viamtyn , ifnull( format(max( case when OH.PAYORTY = 'BILLING' then OH.ORDTAMT when OH.PAYORTY = 'RECEIPT' and OH.VIAMTYN = 'Y' then OH.ORDTAMT else 0 end ),0), 0 ) as ordtamt , WS.ALLGRKY as allgrky from OCOSAL OS inner join WTAKIT WS on WS.COMPKEY = OS.COMPKEY and WS.REFSODC = OS.COOUTKY left join OCOSAH OH on OH.COMPKEY = OS.COMPKEY and OH.COOUTKY = OS.COOUTKY and OH.STEMPYN != 'Y' inner join MCUSMA MH on MH.COMPKEY = OS.COMPKEY and MH.CUSTKEY = OS.CUSTKEY left join MCUSMA MC on MC.COMPKEY = OS.COMPKEY and MC.CUSTKEY = OS.RETAKEY where OS.COMPKEY = #{compkey} and OS.DOCCATE in ('200','300') and OH.COOUTKY IN
#{cooutkyStr}
and OS.MNGWHKY = #{warekey} and OS.OWNERKY = #{ownerky} and WS.ALLGRKY = #{allgrky} group by OS.COMPKEY, OS.POSTDAT, MH.CUNAMLC, MC.CUNAMLC, OS.COOUTKY order by OS.POSTDAT, MH.CUNAMLC, MC.CUNAMLC
